import sys

def count_pairs_with_bounded_sum(n, t, a):
    a.sort()
    count = 0
    left, right = 0, n - 1
    while left < right:
        if a[left] + a[right] <= t:
            count += right - left
            left += 1
        else:
            right -= 1
    return count

def main():
    n, t = map(int, input().split())
    a = list(map(int, input().split()))
    print(count_pairs_with_bounded_sum(n, t, a))

if __name__ == "__main__":
    main()
