import sys

MOD = 1000000007

def main():
    R, C = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(R)]

    dp = [[0] * C for _ in range(R)]
    dp[0][0] = 1

    for i in range(R):
        for j in range(C):
            if grid[i][j] == '.':
                if i > 0:
                    dp[i][j] += dp[i-1][j]
                if j > 0:
                    dp[i][j] += dp[i][j-1]
                dp[i][j] %= MOD

    print(dp[R-1][C-1])

if __name__ == "__main__":
    main()
