import sys

def nearest_smaller_element_on_the_left():
    n = int(input())
    a = list(map(int, input().split()))

    p = [-1] * n
    stack = []

    for i in range(n):
        while stack and a[stack[-1]] >= a[i]:
            stack.pop()
        if stack:
            p[i] = stack[-1]
        stack.append(i)

    return sum(i - p[i] for i in range(n) if p[i] != -1)

