import sys

def max_weight(jobs):
    jobs.sort(key=lambda x: x[1])
    max_pay = [0] * len(jobs)
    max_pay[0] = jobs[0][2]
    for i in range(1, len(jobs)):
        incl = jobs[i][2]
        last_non_conflicting = -1
        for j in range(i-1, -1, -1):
            if jobs[j][1] <= jobs[i][0]:
                last_non_conflicting = j
                break
        if last_non_conflicting != -1:
            incl += max_pay[last_non_conflicting]
        max_pay[i] = max(incl, max_pay[i-1])
    return max_pay[-1]

def main():
    N = int(input())
    jobs = []
    for _ in range(N):
        line = input().split()
        if len(line) != 3:
            raise ValueError("Invalid input")
        s, e, w = map(int, line)
        jobs.append((s, e, w))
    print(max_weight(jobs))

if __name__ == "__main__":
    main()
